mapper.insert:
INSERT INTO woorido.meeting_votes (
  id, meeting_id, status, expires_at, created_at, required_count
) VALUES (
  #{id}, #{meetingId}, #{status}, #{deadline}, #{createdAt}, #{requiredCount}
)

mapper.select:
SELECT * FROM ( SELECT A.*, ROWNUM AS RNUM FROM ( SELECT mv.id AS VOTE_ID, 'MEETING_ATTENDANCE' AS TYPE, m.title AS TITLE, mv.status AS STATUS, m.created_by AS CREATED_BY_ID, u.nickname AS CREATED_BY_NICKNAME, mv.expires_at AS DEADLINE, mv.created_at AS CREATED_AT, (SELECT COUNT(*) FROM woorido.meeting_vote_records mvr WHERE mvr.meeting_vote_id = mv.id AND mvr.choice = 'AGREE') AS AGREE_COUNT, (SELECT COUNT(*) FROM woorido.meeting_vote_records mvr WHERE mvr.meeting_vote_id = mv.id AND mvr.choice = 'DISAGREE') AS DISAGREE_COUNT, (SELECT COUNT(*) FROM woorido.meeting_vote_records mvr WHERE mvr.meeting_vote_id = mv.id) AS TOTAL_VOTE_COUNT FROM woorido.meeting_votes mv JOIN woorido.meetings m ON mv.meeting_id = m.id LEFT JOIN woorido.users u ON m.created_by = u.id WHERE m.challenge_id = #{challengeId}
AND mv.status = #{status}
AND 'MEETING_ATTENDANCE' = #{type}
ORDER BY mv.created_at DESC ) A WHERE ROWNUM <= #{offset} + #{size} ) WHERE RNUM > #{offset}

SELECT COUNT(*)
FROM woorido.meeting_votes mv
JOIN woorido.meetings m ON mv.meeting_id = m.id
WHERE m.challenge_id = #{challengeId}

  AND mv.status = #{status}


  AND 'MEETING_ATTENDANCE' = #{type}

SELECT COUNT(*)
FROM woorido.meeting_vote_records
WHERE meeting_vote_id = #{voteId}
  AND user_id = #{userId}

